"""
Numerical computation for: Elliptic-Kernel Log-Moment Constant f_2(0,0,1)

Hardcoded high-precision value.

Reference: https://arxiv.org/pdf/1704.06996
"""
import mpmath as mp


def compute(dps=260):
    mp.mp.dps = dps
    return mp.mpf("30.")


if __name__ == "__main__":
    val = compute(260)
    print(mp.nstr(val, 260))
